 11‚Üí/**
 12‚Üí * A parser that expects to receive a string consisting of [length] digits, or, if [length] is `null`,
 13‚Üí * a string consisting of any number of digits.
 14‚Üí */
 15‚Üíinternal sealed class NumberConsumer<in Receiver>(
 16‚Üí    /** The number of digits to consume. `null` means that the length is variable. */
 17‚Üí    open val length: Int?,
 18‚Üí    /** The human-readable name of the entity being parsed here. */
 19‚Üí    val whatThisExpects: String
 20‚Üí) {
 21‚Üí    /**
 22‚Üí     * Wholly consumes the given [input]. Should be called with a string consisting of [length] digits, or,
 23‚Üí     * if [length] is `null`, with a string consisting of any number of digits. [consume] itself does not
 24‚Üí     * necessarily check the length of the input string, instead expecting to be passed a valid one.
 25‚Üí     *
 26‚Üí     * Returns `null` on success and a `NumberConsumptionError` on failure.
 27‚Üí     */
 28‚Üí    abstract fun consume(storage: Receiver, input: String): NumberConsumptionError?
 29‚Üí}
