 40‚Üí                val suffix = if (string[0].isDigit()) {
 41‚Üí                    add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(string.takeWhile { it.isDigit() }))))
 42‚Üí                    string.dropWhile { it.isDigit() }
