240‚Üíinternal class CachedFormatStructure<in T>(formats: List<NonConcatenatedFormatStructure<T>>) :
241‚Üí    ConcatenatedFormatStructure<T>(formats) {
242‚Üí    private val cachedFormatter: FormatterStructure<T> = super.formatter()
243‚Üí    private val cachedParser: ParserStructure<T> = super.parser()
244‚Üí
245‚Üí    override fun formatter(): FormatterStructure<T> = cachedFormatter
246‚Üí
247‚Üí    override fun parser(): ParserStructure<T> = cachedParser
