250‚Üíprivate fun <T> basicFormats(format: FormatStructure<T>): List<FieldFormatDirective<T>> = buildList {
251‚Üí    fun rec(format: FormatStructure<T>) {
252‚Üí        when (format) {
253‚Üí            is BasicFormatStructure -> add(format.directive)
254‚Üí            is ConcatenatedFormatStructure -> format.formats.forEach { rec(it) }
255‚Üí            is ConstantFormatStructure -> {}
256‚Üí            is SignedFormatStructure -> rec(format.format)
257‚Üí            is AlternativesParsingFormatStructure -> {
258‚Üí                rec(format.mainFormat); format.formats.forEach { rec(it) }
259‚Üí            }
260‚Üí
261‚Üí            is OptionalFormatStructure -> rec(format.format)
262‚Üí        }
263‚Üí    }
264‚Üí    rec(format)
265‚Üí}
