 34‚Üí        override fun errorMessage() = "expected an Int value"
 35‚Üí    }
 36‚Üí    class TooManyDigits(val maxDigits: Int): NumberConsumptionError {
 37‚Üí        override fun errorMessage() = "expected at most $maxDigits digits"
 38‚Üí    }
 39‚Üí    class TooFewDigits(val minDigits: Int): NumberConsumptionError {
 40‚Üí        override fun errorMessage() = "expected at least $minDigits digits"
 41‚Üí    }
 42‚Üí    class WrongConstant(val expected: String): NumberConsumptionError {
 43‚Üí        override fun errorMessage() = "expected '$expected'"
 44‚Üí    }
 45‚Üí    class Conflicting(val conflicting: Any): NumberConsumptionError {
 46‚Üí        override fun errorMessage() = "attempted to overwrite the existing value '$conflicting'"
 47‚Üí    }
