 50‚Üí/**
 51‚Üí * A parser that accepts an [Int] value in range from `0` to [Int.MAX_VALUE].
 52‚Üí */
 53‚Üí// TODO: should the parser reject excessive padding?
 54‚Üíinternal class UnsignedIntConsumer<in Receiver>(
 55‚Üí    private val minLength: Int?,
 56‚Üí    private val maxLength: Int?,
 57‚Üí    private val setter: AssignableField<Receiver, Int>,
 58‚Üí    name: String,
 59‚Üí    private val multiplyByMinus1: Boolean = false,
 60‚Üí) : NumberConsumer<Receiver>(if (minLength == maxLength) minLength else null, name) {
 61‚Üí
 62‚Üí    init {
 63‚Üí        require(length == null || length in 1..9) { "Invalid length for field $whatThisExpects: $length" }
 64‚Üí    }
 65‚Üí
 66‚Üí    override fun consume(storage: Receiver, input: String): NumberConsumptionError? = when {
 67‚Üí        maxLength != null && input.length > maxLength -> NumberConsumptionError.TooManyDigits(maxLength)
 68‚Üí        minLength != null && input.length < minLength -> NumberConsumptionError.TooFewDigits(minLength)
 69‚Üí        else -> when (val result = input.toIntOrNull()) {
 70‚Üí            null -> NumberConsumptionError.ExpectedInt
 71‚Üí            else -> setter.setWithoutReassigning(storage, if (multiplyByMinus1) -result else result)
 72‚Üí        }
 73‚Üí    }
 74‚Üí}
